#define BIGRND 0x7fffffff
#define ETA 0.3f
#define MOMENTUM 0.3f
#define WIDTH 16
#define HEIGHT 16
#define BLOCK_SIZE 16

float squash(float x) {
    return 1.0f / (1.0f + exp(-x));
}

kernel void bpnn_layerforward_ocl(global float *l1,
                                  global float *l2,
                                  global float *conn,
                                  global float *partial_sum,
                                  local float *local_conn,
                                  local float *local_l1,
                                  int n1,
                                  int n2) {
    int j = get_global_id(0);
    int block_idx = get_global_id(1);
    int local_j = get_local_id(0);
    int local_block = get_local_id(1);

    if (j >= n2) return;

    float sum = 0.0f;

    int start_k = block_idx * BLOCK_SIZE;
    int end_k = start_k + BLOCK_SIZE;
    if (end_k > n1 + 1) end_k = n1 + 1;

    for (int k = start_k; k < end_k; k++) {
        if (k <= n1) {
            float weight = conn[k * (n2 + 1) + j];
            float input = l1[k];
            sum += weight * input;
        }
    }

    partial_sum[block_idx * n2 + (j - 1)] = sum;
}

kernel void bpnn_adjust_weights_ocl(global float *delta,
                                    int ndelta,
                                    global float *ly,
                                    int nly,
                                    global float *w,
                                    global float *oldw) {
    int j = get_global_id(0) + 1;
    int k = get_global_id(1);

    if (j > ndelta || k > nly) return;

    float ly_val = (k == 0) ? 1.0f : ly[k];
    float delta_val = delta[j];

    float new_dw = (ETA * delta_val * ly_val) + (MOMENTUM * oldw[k * (ndelta + 1) + j]);

    w[k * (ndelta + 1) + j] += new_dw;
    oldw[k * (ndelta + 1) + j] = new_dw;
}
